import { Callback, TFunction } from 'i18next';
import { i18nSdk, getI18nLanguageRequestPayload } from './services';
import { i18nInitProps } from './const';
import i18n, { initReactI18next, sptChangeLanguage } from '.';
import ICU from 'i18next-icu';

/**
 * @param options
 * @returns 返回指定部件指定语言json数据
 */
export function getLanguage(options: getI18nLanguageRequestPayload) {
    return new Promise<any>((resolve, reject) => {
        i18nSdk
            .getLanguageFile(options)
            .then((res: any) => {
                // 304命中缓存去拿数据
                if (res.status === 200) {
                    // TODO更新缓存
                    resolve(res.data);
                } else {
                    reject('拉取翻译失败');
                }
            })
            .catch((err: any) => reject(err));
    });
}
/**
 * @param options
 * @param isMain 默认为false 为true会进行加载common 和后端common数据
 * @returns 返回应用必需翻译数据
 */
export const getProjectLanguage = (options: i18nInitProps) =>
    new Promise<TFunction>((resolve, reject) => {
        // 获取指定语言翻译
        Promise.all(
            options?.componentList?.map((component: string) =>
                getLanguage({ ...options, component })
            )
        )
            .then((resList: any[]) => {
                const source = Object.assign({}, ...resList);
                // 拿取common部件的index
                const commonIndex = options?.componentList?.findIndex(
                    (component) => component === 'common'
                );
                // 如果找到了位置，设置localStorage缓存
                if (~commonIndex) {
                    // 获取现有的缓存key
                    // TODO 兼容 dev 后续需要删掉
                    const cacheData = getLanguageCache({ ...options, component: 'common' });
                    setLanguageCache(
                        { ...options, component: options?.componentList?.[commonIndex] },
                        { ...cacheData, ...resList[commonIndex] }
                    );
                }
                resolve(source);
            })
            .catch((error: any) => {
                console.log(reject(error));
            });
    });

/**
 *
 * @param options 语言配置项
 * 包含dev的项目设置dev缓存
 * @returns
 */
export const getLanguageCache = (options: getI18nLanguageRequestPayload) => {
    try {
        // 返回空对象
        return JSON.parse(
            localStorage.getItem(
                `i18n_cache_common_${options.language}_${
                    // TODO 兼容 dev 后续需要删掉
                    options?.project?.includes('local') || options?.project?.includes('dev')
                        ? 'dev'
                        : 'prd'
                }`
            ) || '{}'
        );
    } catch (error) {
        console.log(error);
        // 返回空对象source
        return {};
    }
};
/**
 *
 * @param options 语言配置项
 * @param value 数据源
 * @returns
 */
export const setLanguageCache = (options: getI18nLanguageRequestPayload, value: any) => {
    try {
        localStorage.setItem(
            `i18n_cache_common_${options.language}_${
                // TODO 兼容 dev 后续需要删掉
                options?.project?.includes('local') || options?.project?.includes('dev')
                    ? 'dev'
                    : 'prd'
            }`,
            JSON.stringify(value || '')
        );
    } catch (error) {
        console.log(error);
    }
};

type i18nInitOptionProps = {
    domainUrl: string;
    language: string;
    componentList: string[];
    project: string;
};
/**
 * 调用 i18n init 初始化
 * @param options
 * @param data
 */
export const i18nInit = async (options: i18nInitOptionProps, data: { [key: string]: string }) => {
    await i18n
        .use(ICU)
        .use(initReactI18next)
        .init({
            lng: options.language,
            resources: {
                [options?.language]: {
                    // 如果存在source文件去灌入数据
                    translation: { ...data }
                }
            },
            saveMissing: false,
            interpolation: {
                escapeValue: false // not needed for react as it escapes by default,
            }
        });
};

/** 异步更新翻译资源
 *
 * @param options
 * @param component // 需要异步请求的部件
 * @param allData
 * @param originalSource
 */

export const asyncUpdateI18n = async (options: i18nInitOptionProps, component: string) => {
    try {
        const newOptions = { ...options };
        // backend-common 单独访问 spotter 项目
        if (component === 'backend-common') {
            if (options.project.includes('local')||options.project.includes('dev')) {
                newOptions.project = 'spotter-dev';
            } else {
                newOptions.project = 'spotter';
            }
        }
        const res = await getLanguage({ ...newOptions, component });
        // 添加异步请求的资源
        i18n.addResourceBundle(newOptions.language!, 'translation', { ...res }, true, true);
    } catch (initError) {
        console.error('异步添加失败：', initError);
    }
};
